const INPUT_FIELD = "design";
const OUTPUT_FIELD = "design_api";

const CONFIG = {
  container_types: new Set(["rectangle", "ellipse", "diamond", "frame"]),
  screen_types: new Set(["rectangle", "frame"]),
  min_container_width: 24,
  min_container_height: 24,
  min_container_area: 800,
  top_level_containment_ratio: 0.96,
  top_level_center_overlap_ratio: 0.85,
  screen_area_percentile: 0.85,
  screen_child_count_percentile: 0.85,
  min_screen_area: 120000,
  min_screen_width: 280,
  min_screen_height: 320,
  min_screen_child_count: 6,
  screen_membership_overlap_ratio: 0.35,
  screen_membership_margin: 24,
  overlay_min_width: 160,
  overlay_min_height: 100,
  overlay_min_child_count: 2,
  modal_min_width: 420,
  modal_min_height: 260,
  modal_min_area: 90000,
  component_containment_ratio: 0.9,
  component_center_overlap_ratio: 0.6,
  label_vertical_gap: 28,
  label_horizontal_gap: 20,
  label_horizontal_overlap_ratio: 0.45,
  title_top_band_ratio: 0.22,
  title_above_margin: 36,
  title_horizontal_margin: 48,
};

const NUMERIC_RE = /^[\W\d_]+$/;
const WHITESPACE_RE = /\s+/g;
const CONTROL_CHAR_ESCAPES = {
  "\b": "\\b",
  "\f": "\\f",
  "\n": "\\n",
  "\r": "\\r",
  "\t": "\\t",
};

function cleanText(value) {
  if (value === undefined || value === null) {
    return null;
  }

  const cleaned = String(value).replace(WHITESPACE_RE, " ").trim();
  return cleaned || null;
}

function createBounds(left, top, right, bottom) {
  return {
    left,
    top,
    right,
    bottom,
    get width() {
      return Math.max(0, this.right - this.left);
    },
    get height() {
      return Math.max(0, this.bottom - this.top);
    },
    get area() {
      return this.width * this.height;
    },
    get center() {
      return [this.left + this.width / 2, this.top + this.height / 2];
    },
  };
}

function expandBounds(bounds, margin) {
  return createBounds(
    bounds.left - margin,
    bounds.top - margin,
    bounds.right + margin,
    bounds.bottom + margin,
  );
}

function elementBounds(element) {
  const x = Number(element.x || 0);
  const y = Number(element.y || 0);
  const width = Number(element.width || 0);
  const height = Number(element.height || 0);

  const xs = [x, x + width];
  const ys = [y, y + height];

  const points = element.points || [];
  if (Array.isArray(points)) {
    for (const point of points) {
      if (Array.isArray(point) && point.length >= 2) {
        xs.push(x + Number(point[0]));
        ys.push(y + Number(point[1]));
      }
    }
  }

  return createBounds(
    Math.min(...xs),
    Math.min(...ys),
    Math.max(...xs),
    Math.max(...ys),
  );
}

function pointInBounds(point, bounds) {
  const [x, y] = point;
  return bounds.left <= x && x <= bounds.right && bounds.top <= y && y <= bounds.bottom;
}

function intersectionArea(a, b) {
  const left = Math.max(a.left, b.left);
  const right = Math.min(a.right, b.right);
  const top = Math.max(a.top, b.top);
  const bottom = Math.min(a.bottom, b.bottom);
  if (right <= left || bottom <= top) {
    return 0;
  }
  return (right - left) * (bottom - top);
}

function overlapRatio(inner, outer) {
  return intersectionArea(inner, outer) / Math.max(inner.area, 1);
}

function percentile(values, q) {
  if (!values.length) {
    return 0;
  }

  const ordered = [...values].map(Number).sort((a, b) => a - b);
  if (ordered.length === 1) {
    return ordered[0];
  }

  const position = (ordered.length - 1) * Math.max(0, Math.min(1, q));
  const lower = Math.floor(position);
  const upper = Math.ceil(position);
  if (lower === upper) {
    return ordered[lower];
  }

  const fraction = position - lower;
  return ordered[lower] * (1 - fraction) + ordered[upper] * fraction;
}

function makeNode(raw, index) {
  return {
    id: raw.id || `element-${index}`,
    sourceElementId: raw.id || `element-${index}`,
    type: raw.type || "unknown",
    text: cleanText(raw.text || raw.originalText),
    fontSize: raw.fontSize,
    bounds: elementBounds(raw),
    zIndex: index,
  };
}

function isContainer(node) {
  const bounds = node.bounds;
  return (
    CONFIG.container_types.has(node.type) &&
    bounds.width >= CONFIG.min_container_width &&
    bounds.height >= CONFIG.min_container_height &&
    bounds.area >= CONFIG.min_container_area
  );
}

function isTopLevelContainer(candidate, containers) {
  const childBounds = candidate.bounds;
  const childCenter = childBounds.center;

  for (const parent of containers) {
    if (parent.id === candidate.id) {
      continue;
    }

    const parentBounds = parent.bounds;
    if (parentBounds.area <= childBounds.area * 1.05) {
      continue;
    }

    const ratio = overlapRatio(childBounds, parentBounds);
    if (ratio >= CONFIG.top_level_containment_ratio) {
      return false;
    }

    if (pointInBounds(childCenter, parentBounds) && ratio >= CONFIG.top_level_center_overlap_ratio) {
      return false;
    }
  }

  return true;
}

function countMembers(container, elements, margin = 0) {
  const bounds = expandBounds(container.bounds, margin);
  let total = 0;

  for (const element of elements) {
    if (element.id === container.id) {
      continue;
    }

    const box = element.bounds;
    if (
      pointInBounds(box.center, bounds) ||
      overlapRatio(box, bounds) >= CONFIG.screen_membership_overlap_ratio
    ) {
      total += 1;
    }
  }

  return total;
}

function detectScreens(elements) {
  const containers = elements.filter(
    (node) => isContainer(node) && CONFIG.screen_types.has(node.type),
  );
  if (!containers.length) {
    return [];
  }

  let topLevel = containers.filter((node) => isTopLevelContainer(node, containers));
  if (!topLevel.length) {
    topLevel = containers;
  }

  topLevel = topLevel.filter(
    (node) =>
      node.bounds.width >= CONFIG.min_screen_width &&
      node.bounds.height >= CONFIG.min_screen_height,
  );
  if (!topLevel.length) {
    return [];
  }

  const memberCounts = Object.fromEntries(
    topLevel.map((node) => [node.id, countMembers(node, elements)]),
  );
  const areaThreshold = Math.max(
    CONFIG.min_screen_area,
    percentile(
      topLevel.map((node) => node.bounds.area),
      CONFIG.screen_area_percentile,
    ),
  );
  const childThreshold = Math.max(
    CONFIG.min_screen_child_count,
    percentile(Object.values(memberCounts), CONFIG.screen_child_count_percentile),
  );

  let screens = topLevel.filter(
    (node) =>
      node.bounds.area >= areaThreshold || memberCounts[node.id] >= childThreshold,
  );

  if (!screens.length) {
    screens = [
      topLevel.reduce((best, node) => {
        const bestScore = [best.bounds.area, memberCounts[best.id]];
        const nextScore = [node.bounds.area, memberCounts[node.id]];
        return nextScore[0] > bestScore[0] || (nextScore[0] === bestScore[0] && nextScore[1] > bestScore[1])
          ? node
          : best;
      }),
    ];
  }

  return screens.sort(
    (a, b) => a.bounds.top - b.bounds.top || a.bounds.left - b.bounds.left || a.zIndex - b.zIndex,
  );
}

function inferRootName(root, textNodes, usedNames, defaultPrefix, topBandRatio = 0.22) {
  const bounds = root.bounds;
  const titleBandBottom = bounds.top + bounds.height * topBandRatio;
  const candidates = [];

  for (const node of textNodes) {
    const text = node.text;
    if (!text || NUMERIC_RE.test(text)) {
      continue;
    }

    const nodeBounds = node.bounds;
    if (nodeBounds.right < bounds.left - CONFIG.title_horizontal_margin) {
      continue;
    }
    if (nodeBounds.left > bounds.right + CONFIG.title_horizontal_margin) {
      continue;
    }
    if (nodeBounds.top < bounds.top - CONFIG.title_above_margin) {
      continue;
    }
    if (nodeBounds.top > titleBandBottom) {
      continue;
    }

    const distance =
      Math.max(0, nodeBounds.left - bounds.left) +
      Math.max(0, nodeBounds.top - bounds.top);
    const fontSize = Number(node.fontSize || 16);
    const alphaBonus = [...text].filter((char) => /[A-Za-z]/.test(char)).length;
    const score = fontSize * 2 + Math.min(alphaBonus, 30) - distance / 30;
    candidates.push([score, text]);
  }

  let baseName = `${defaultPrefix}_${root.id}`;
  if (candidates.length) {
    candidates.sort((a, b) => b[0] - a[0] || a[1].localeCompare(b[1]));
    baseName = candidates[0][1];
  }

  const suffix = usedNames[baseName] || 0;
  usedNames[baseName] = suffix + 1;
  return suffix === 0 ? baseName : `${baseName} (${suffix + 1})`;
}

function distanceBetween(a, b) {
  return Math.hypot(a[0] - b[0], a[1] - b[1]);
}

function rootMembershipScore(element, root) {
  const rootBounds = expandBounds(root.bounds, CONFIG.screen_membership_margin);
  const elementBoundsValue = element.bounds;
  const centerInside = pointInBounds(elementBoundsValue.center, rootBounds);
  const overlap = overlapRatio(elementBoundsValue, rootBounds);

  if (!centerInside && overlap < CONFIG.screen_membership_overlap_ratio) {
    return null;
  }

  const distance = distanceBetween(rootBounds.center, elementBoundsValue.center);
  const diagonal = Math.hypot(rootBounds.width, rootBounds.height) || 1;
  const distancePenalty = distance / diagonal;
  return (centerInside ? 1.5 : 0) + overlap * 2 - distancePenalty;
}

function assignElementsToRoots(elements, roots) {
  const assignments = Object.fromEntries(roots.map((root) => [root.id, []]));
  const rootIds = new Set(roots.map((root) => root.id));
  const remaining = [];

  for (const element of elements) {
    if (rootIds.has(element.id)) {
      continue;
    }

    let bestRoot = null;
    let bestScore = null;

    for (const root of roots) {
      const score = rootMembershipScore(element, root);
      if (score === null) {
        continue;
      }
      if (bestScore === null || score > bestScore) {
        bestScore = score;
        bestRoot = root;
      }
    }

    if (!bestRoot) {
      remaining.push(element);
    } else {
      assignments[bestRoot.id].push(element);
    }
  }

  return [assignments, remaining];
}

function detectStandaloneOverlays(elements) {
  const containers = elements.filter(
    (node) =>
      isContainer(node) &&
      node.bounds.width >= CONFIG.overlay_min_width &&
      node.bounds.height >= CONFIG.overlay_min_height,
  );
  if (!containers.length) {
    return [];
  }

  const topLevel = containers.filter((node) => isTopLevelContainer(node, containers));
  const overlays = topLevel.filter(
    (node) => countMembers(node, elements) >= CONFIG.overlay_min_child_count,
  );

  return overlays.sort(
    (a, b) => a.bounds.top - b.bounds.top || a.bounds.left - b.bounds.left || a.zIndex - b.zIndex,
  );
}

function componentParentScore(child, parent) {
  const childBounds = child.bounds;
  const parentBounds = parent.bounds;

  if (parentBounds.area <= childBounds.area * 1.01) {
    return null;
  }

  const centerInside = pointInBounds(childBounds.center, parentBounds);
  const ratio = overlapRatio(childBounds, parentBounds);

  if (!centerInside && ratio < CONFIG.component_containment_ratio) {
    return null;
  }
  if (centerInside && ratio < CONFIG.component_center_overlap_ratio) {
    return null;
  }

  const freeSpace = Math.max(parentBounds.area - childBounds.area, 1);
  return ratio * 3 + (centerInside ? 1 : 0) - Math.log(freeSpace);
}

function horizontalOverlapRatio(a, b) {
  const overlap = Math.max(0, Math.min(a.right, b.right) - Math.max(a.left, b.left));
  return overlap / Math.max(Math.min(a.width, b.width), 1);
}

function verticalGap(a, b) {
  if (a.bottom <= b.top) {
    return b.top - a.bottom;
  }
  if (b.bottom <= a.top) {
    return a.top - b.bottom;
  }
  return 0;
}

function isMeaningfulText(node) {
  return Boolean(node.text && !NUMERIC_RE.test(node.text));
}

function attachTextLabels(textNodes, objectNodes) {
  const labels = {};

  for (const textNode of textNodes) {
    if (!isMeaningfulText(textNode)) {
      continue;
    }

    const textBounds = textNode.bounds;
    let bestTarget = null;
    let bestScore = null;

    for (const candidate of objectNodes) {
      const candidateBounds = candidate.bounds;
      let score = null;

      if (pointInBounds(textBounds.center, candidateBounds)) {
        score = 5 - Math.log(Math.max(candidateBounds.area, 1));
      } else {
        const gap = verticalGap(textBounds, candidateBounds);
        const overlap = horizontalOverlapRatio(textBounds, candidateBounds);
        const closeAbove = textBounds.bottom <= candidateBounds.top + CONFIG.label_vertical_gap;
        const closeLeft =
          Math.abs(textBounds.right - candidateBounds.left) <= CONFIG.label_horizontal_gap &&
          overlap >= 0.25;

        if (
          gap <= CONFIG.label_vertical_gap &&
          overlap >= CONFIG.label_horizontal_overlap_ratio &&
          closeAbove
        ) {
          score =
            3 -
            gap / Math.max(CONFIG.label_vertical_gap, 1) -
            Math.log(Math.max(candidateBounds.area, 1));
        } else if (closeLeft) {
          score =
            2 -
            Math.abs(textBounds.right - candidateBounds.left) /
              Math.max(CONFIG.label_horizontal_gap, 1);
        }
      }

      if (score === null) {
        continue;
      }

      if (bestScore === null || score > bestScore) {
        bestScore = score;
        bestTarget = candidate;
      }
    }

    if (!bestTarget) {
      continue;
    }

    labels[bestTarget.id] = labels[bestTarget.id] || [];
    if (!labels[bestTarget.id].includes(textNode.text)) {
      labels[bestTarget.id].push(textNode.text);
    }
  }

  return labels;
}

function classifyOverlayKind(bounds, referenceBounds) {
  if (referenceBounds) {
    const widthRatio = bounds.width / Math.max(referenceBounds.width, 1);
    const heightRatio = bounds.height / Math.max(referenceBounds.height, 1);
    const detached =
      bounds.left > referenceBounds.left + referenceBounds.width * 0.04 &&
      bounds.right < referenceBounds.right - referenceBounds.width * 0.04 &&
      bounds.top > referenceBounds.top + referenceBounds.height * 0.04 &&
      bounds.bottom < referenceBounds.bottom - referenceBounds.height * 0.04;
    const centered =
      referenceBounds.left + referenceBounds.width * 0.15 <= bounds.center[0] &&
      bounds.center[0] <= referenceBounds.right - referenceBounds.width * 0.15 &&
      referenceBounds.top + referenceBounds.height * 0.12 <= bounds.center[1] &&
      bounds.center[1] <= referenceBounds.bottom - referenceBounds.height * 0.12;

    if (centered && detached && widthRatio >= 0.16 && heightRatio >= 0.14) {
      return widthRatio >= 0.28 || heightRatio >= 0.26 ? "modal" : "dialog";
    }
  }

  if (
    bounds.width >= CONFIG.modal_min_width ||
    bounds.height >= CONFIG.modal_min_height ||
    bounds.area >= CONFIG.modal_min_area
  ) {
    return "modal";
  }

  return "dialog";
}

function inferObjectKind(node, childNodes, labels, rootBounds) {
  const overlayKind = rootBounds ? classifyOverlayKind(node.bounds, rootBounds) : null;
  if (overlayKind && rootBounds && node.bounds.area < rootBounds.area * 0.85) {
    return overlayKind;
  }
  if (labels.length && node.bounds.height <= 72) {
    return "control";
  }
  if (childNodes.length) {
    return "group";
  }
  if (node.bounds.height <= 88) {
    return "control";
  }
  return "container";
}

function boundsToBox(bounds) {
  return [
    Number(bounds.left.toFixed(2)),
    Number(bounds.top.toFixed(2)),
    Number(bounds.width.toFixed(2)),
    Number(bounds.height.toFixed(2)),
  ];
}

function serializeObject(node, childrenMap, labelMap, rootBounds) {
  const childNodes = [...(childrenMap[node.id] || [])].sort(
    (a, b) => a.bounds.top - b.bounds.top || a.bounds.left - b.bounds.left || a.zIndex - b.zIndex,
  );
  const labels = labelMap[node.id] || [];

  const payload = {
    id: node.id,
    sourceId: node.sourceElementId,
    kind: inferObjectKind(node, childNodes, labels, rootBounds),
    type: node.type,
    box: boundsToBox(node.bounds),
  };

  if (labels.length) {
    payload.labels = labels;
  }
  if (childNodes.length) {
    payload.objects = childNodes.map((child) =>
      serializeObject(child, childrenMap, labelMap, rootBounds),
    );
  }

  return payload;
}

function buildReducedObjects(elements, rootBounds) {
  if (!elements.length) {
    return [];
  }

  const objectNodes = elements.filter((node) => isContainer(node));
  if (!objectNodes.length) {
    return [];
  }

  const parentMap = {};
  const sortedNodes = [...objectNodes].sort(
    (a, b) => a.bounds.area - b.bounds.area || a.zIndex - b.zIndex,
  );

  for (const node of sortedNodes) {
    let bestParent = null;
    let bestScore = null;

    for (const parent of objectNodes) {
      if (parent.id === node.id) {
        continue;
      }

      const score = componentParentScore(node, parent);
      if (score === null) {
        continue;
      }
      if (bestScore === null || score > bestScore) {
        bestScore = score;
        bestParent = parent.id;
      }
    }

    parentMap[node.id] = bestParent;
  }

  const childrenMap = {};
  const roots = [];

  for (const node of objectNodes) {
    const parentId = parentMap[node.id];
    if (parentId) {
      childrenMap[parentId] = childrenMap[parentId] || [];
      childrenMap[parentId].push(node);
    } else {
      roots.push(node);
    }
  }

  const labelMap = attachTextLabels(
    elements.filter((node) => node.type === "text"),
    objectNodes,
  );

  return roots
    .sort((a, b) => a.bounds.top - b.bounds.top || a.bounds.left - b.bounds.left || a.zIndex - b.zIndex)
    .map((node) => serializeObject(node, childrenMap, labelMap, rootBounds));
}

function transformExcalidraw(data) {
  const rawElements = Array.isArray(data.elements) ? data.elements : [];
  const elements = rawElements
    .filter((raw) => raw && typeof raw === "object" && !raw.isDeleted)
    .map((raw, index) => makeNode(raw, index));

  const screens = detectScreens(elements);
  const [screenAssignments, remaining] = assignElementsToRoots(elements, screens);
  const overlays = detectStandaloneOverlays(remaining);
  const [overlayAssignments] = assignElementsToRoots(remaining, overlays);
  const textNodes = elements.filter((node) => node.type === "text");

  const usedScreenNames = {};
  const usedOverlayNames = {};

  const serializedScreens = screens.map((screen, index) => ({
    id: `screen-${index + 1}`,
    name: inferRootName(screen, textNodes, usedScreenNames, "screen"),
    sourceId: screen.sourceElementId,
    box: boundsToBox(screen.bounds),
    objects: buildReducedObjects(screenAssignments[screen.id] || [], screen.bounds),
  }));

  const serializedModals = [];
  const serializedDialogs = [];

  overlays.forEach((overlay, index) => {
    const kind = classifyOverlayKind(overlay.bounds, null);
    const payload = {
      id: `${kind}-${index + 1}`,
      name: inferRootName(overlay, textNodes, usedOverlayNames, kind, 0.3),
      sourceId: overlay.sourceElementId,
      box: boundsToBox(overlay.bounds),
      objects: buildReducedObjects(overlayAssignments[overlay.id] || [], overlay.bounds),
    };

    if (kind === "modal") {
      serializedModals.push(payload);
    } else {
      serializedDialogs.push(payload);
    }
  });

  return {
    meta: {
      source: data.source,
      type: data.type,
      version: data.version,
      elementCount: elements.length,
      screenCount: serializedScreens.length,
      modalCount: serializedModals.length,
      dialogCount: serializedDialogs.length,
    },
    screens: serializedScreens,
    modals: serializedModals,
    dialogs: serializedDialogs,
  };
}

function escapeControlCharsInJsonStrings(value) {
  let result = "";
  let inString = false;
  let escaped = false;

  for (let index = 0; index < value.length; index += 1) {
    const char = value[index];

    if (inString) {
      if (escaped) {
        result += char;
        escaped = false;
        continue;
      }

      if (char === "\\") {
        result += char;
        escaped = true;
        continue;
      }

      if (char === '"') {
        result += char;
        inString = false;
        continue;
      }

      const code = char.charCodeAt(0);
      if (code <= 0x1f) {
        result += CONTROL_CHAR_ESCAPES[char] || '\\' + 'u' + code.toString(16).padStart(4, '0');
        continue;
      }

      result += char;
      continue;
    }

    if (char === '"') {
      inString = true;
    }

    result += char;
  }

  return result;
}

function parseJsonObject(rawDesign, itemIndex) {
  const attempts = [rawDesign, escapeControlCharsInJsonStrings(rawDesign)];
  let lastError = null;

  for (const candidate of attempts) {
    try {
      const parsed = JSON.parse(candidate);
      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
        return parsed;
      }

      throw new Error("Item " + itemIndex + ": field '" + INPUT_FIELD + "' must decode to a JSON object.");
    } catch (error) {
      lastError = error;
    }
  }

  throw new Error("Item " + itemIndex + ": field '" + INPUT_FIELD + "' is not valid JSON: " + lastError.message);
}

function parseDesign(rawDesign, itemIndex) {
  if (rawDesign && typeof rawDesign === "object" && !Array.isArray(rawDesign)) {
    return rawDesign;
  }

  if (typeof rawDesign === "string") {
    return parseJsonObject(rawDesign, itemIndex);
  }

  throw new Error("Item " + itemIndex + ": field '" + INPUT_FIELD + "' must be a JSON string or object.");
}

const items = $input.all();

return items.map((item, itemIndex) => {
  const sourceJson = item.json || {};
  if (!(INPUT_FIELD in sourceJson)) {
    throw new Error(`Item ${itemIndex}: missing '${INPUT_FIELD}' field.`);
  }

  const design = parseDesign(sourceJson[INPUT_FIELD], itemIndex);
  const reducedJson = transformExcalidraw(design);

  return {
    json: {
      [OUTPUT_FIELD]: reducedJson,
    },
  };
});

const item = $input.first();
const json = item?.json ?? {};
const openapiYaml = String(json.response ?? '').trim();
if (!openapiYaml) throw new Error('OpenAPI YAML draft is missing.');
const revisionNumber = Math.max(0, Math.trunc(Number(json.revisionNumber ?? 0) || 0));
const zipDownloadUrl = String(json.zipDownloadUrl ?? '').trim();
if (!zipDownloadUrl) throw new Error('Review ZIP download URL is missing.');
const zipDownloadToken = String(json.zipDownloadToken ?? '').trim();
if (!zipDownloadToken) throw new Error('Review ZIP download token is missing.');
const downloadLinkHtml = '<p><a href="' + zipDownloadUrl + '" download target="_blank" rel="noopener noreferrer">Download current API ZIP</a></p>';
const output = {
  json: { ...json, openapiYaml, revisionNumber, zipDownloadUrl, zipDownloadToken, downloadLinkHtml },
};
if (item.binary && Object.keys(item.binary).length > 0) {
  output.binary = item.binary;
}
return [output];

const item = $input.first();
const json = item.json ?? {};
const openapiYaml = String(json.openapiYaml ?? '').trim();
if (!openapiYaml) throw new Error('OpenAPI YAML draft is missing for patch generation.');
const reviewerFeedback = String(json.feedback ?? json.Feedback ?? '').trim() || 'Reviewer requested changes without additional details.';
const revisionNumber = Math.max(0, Math.trunc(Number(json.revisionNumber ?? 0) || 0)) + 1;
const numberedYaml = openapiYaml.split(/\r?\n/).map((line, index) => String(index + 1) + ': ' + line).join('\n');
const patchPrompt = [
  'You are correcting an existing OpenAPI YAML draft.',
  'Use ONLY the current draft and the reviewer feedback below.',
  'Return ONLY line replacements in this exact format:',
